// Bandwidth Optimizer - Reduce data transfer untuk 900 siswa
window.BandwidthOptimizer={_enabled:!0,_compressionLevel:9,_imageQuality:.75,_cacheSize:50,init:function(){this._setupImageOptimization(),this._setupDataCompression(),this._setupNetworkMonitoring(),console.log("[BandwidthOptimizer] ✅ Initialized")},_setupImageOptimization:function(){if(!window.navigator.connection)return;const e=window.navigator.connection.effectiveType;console.log(`[BandwidthOptimizer] Network: ${e}`);const t=document.querySelectorAll("img[data-src]");t.forEach(t=>{const i=t.dataset.src;if(!i)return;const n=new Image;n.onload=()=>{t.src=i,t.removeAttribute("data-src")},n.src=i})},_setupDataCompression:function(){const e=window.localStorage.getItem("CBT_CACHE_JADWAL");if(!e)return;try{const t=JSON.parse(e),i=JSON.stringify(t).length;console.log(`[BandwidthOptimizer] Cache size: ${(i/1024).toFixed(2)} KB`),i>5242880&&(console.warn("[BandwidthOptimizer] Cache > 5MB, clearing old entries"),this._clearOldCache())}catch(e){console.warn("[BandwidthOptimizer] Cache parse error:",e)}},_clearOldCache:function(){const e=["CBT_CACHE_JADWAL","CBT_CACHE_SOAL","CBT_EXAM_SESSION"];e.forEach(e=>{const t=window.localStorage.getItem(`${e}_TIME`);if(t){const i=Date.now()-parseInt(t);i>86400e3&&(window.localStorage.removeItem(e),window.localStorage.removeItem(`${e}_TIME`),console.log(`[BandwidthOptimizer] Cleared old cache: ${e}`))}}),console.log("[BandwidthOptimizer] Cache cleanup completed")},_setupNetworkMonitoring:function(){if(!window.navigator.connection)return;const e=()=>{const t=window.navigator.connection.effectiveType,i=window.navigator.connection.downlink;console.log(`[BandwidthOptimizer] Network changed: ${t} (${i} Mbps)`),this._adjustQualityBasedOnNetwork(t)};window.navigator.connection.addEventListener("change",e)},_adjustQualityBasedOnNetwork:function(e){switch(e){case"4g":this._imageQuality=.9,this._compressionLevel=6;break;case"3g":this._imageQuality=.7,this._compressionLevel=9;break;case"2g":this._imageQuality=.5,this._compressionLevel=9;break;default:this._imageQuality=.75,this._compressionLevel=9}console.log(`[BandwidthOptimizer] Quality adjusted: ${this._imageQuality}, Compression: ${this._compressionLevel}`)},getStats:function(){return{enabled:this._enabled,compressionLevel:this._compressionLevel,imageQuality:this._imageQuality,cacheSize:this._cacheSize}}};document.addEventListener("DOMContentLoaded",()=>{window.BandwidthOptimizer.init()});
